#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

class Solution {
public:
    Node* mergeSort(Node* head, Node* tail) {
        if (head == NULL || tail == NULL) {
            return NULL;
        }
        dummy = new Node(0);
        dummy->next = head;
        newTail = tail;
        prev = dummy;
        while (head != tail) {
            if (head->next == tail) {
                break;
            }
            if (head->val > newTail->val) {
                node = new Node(head->val);
                prev->next = node;
                node->next = head;
                prev = node;
                head = head->next;
                newTail = node;
            } else if (head->next == newTail) {
                node = new Node(head->val);
                prev->next = node;
                node->next = head;
                prev = node;
                newTail = node;
                head = head->next;
            } else {
                prev = head;
                head = head->next;
            }
        }
        newTail->next = NULL;
        return dummy->next;
    }

    void mergeSortRecur(Node* head, Node* tail) {
        if (head == tail) {
            return;
        }
        mergeSortRecur(head, tail->next);
        while (head->next != tail) {
            if (head->val > head->next->val) {
                Node* node = new Node(head->val);
                tail->next = node;
                node->next = head->next;
                node->prev = tail;
                head->next->prev = node;
                tail = node;
            }
            head = head->next;
        }
    }
};

int main() {
    // Example code
    Node* head = new Node(1);
    Node* tail = new Node(2);
    head->next = tail;
    tail->prev = head;

    Solution solution;
    Node* newHead = solution.mergeSort(head, tail);
